use crate::decoders::{Crack, CrackResult, Decoder, check_string_success};use crate::checkers::CheckerTypes;use std::marker::PhantomData;pub struct Base58Decoder;impl Crack for Decoder<Base58Decoder> {    fn crack(&self, text: &str, checker: &CheckerTypes) -> CrackResult {        let mut result = CrackResult::new(self.get_name(), self.get_description(), self.get_link());        result.encrypted_text = text.to_string();        if let Ok(decoded_bytes) = bs58::decode(text).into_vec() {            if let Ok(decoded_str) = String::from_utf8(decoded_bytes) {                if check_string_success(&decoded_str, text) {                    let check_result = checker.check_text(&decoded_str);                    if check_result.is_identified {                        result.success = true;                        result.unencrypted_text = Some(vec![decoded_str]);                        result.checker_name = check_result.checker_name;                        return result;                    }                }            }        }        result    }    fn get_name(&self) -> &'static str { "Base58" }    fn get_popularity(&self) -> f32 { 0.5 }    fn get_tags(&self) -> &'static [&'static str] { &["base58", "decoder", "base"] }    fn get_description(&self) -> &'static str { "Base58 is a binary-to-text encoding scheme used in cryptocurrencies, similar to Base64 but with a human-friendly alphabet." }    fn get_link(&self) -> &'static str { "https://en.wikipedia.org/wiki/Base58" }}impl Decoder<Base58Decoder> {    pub fn new() -> Self {        Decoder {            name: "Base58",            description: "Base58 is a binary-to-text encoding scheme used in cryptocurrencies.",            link: "https://en.wikipedia.org/wiki/Base58",            tags: vec!["base58", "decoder", "base"],            popularity: 0.5,            phantom: PhantomData,        }    }}



